<script setup lang="ts">
import { Head, Link, usePage } from '@inertiajs/vue3';import { Camera, Flame, Heart, MessageCircle, Mic, MicOff, Radio, Send, Share2, Users, Video, VideoOff, X } from '@lucide/vue';import { nextTick, onMounted, onUnmounted, ref } from 'vue';import AppShell from '../../Layouts/AppShell.vue';
const props=defineProps<{initialStream?:string}>();const page=usePage(),me=Number((page.props.auth as any)?.user?.id),streams=ref<any[]>([]),room=ref<any>(),messages=ref<any[]>([]),title=ref(''),description=ref(''),body=ref(''),creating=ref(false),camera=ref<MediaStream>(),preview=ref<HTMLVideoElement>(),remoteVideo=ref<HTMLVideoElement>(),muted=ref(false),videoOff=ref(false),error=ref(''),permissionHelp=ref(false),requesting=ref(false),reaction=ref('');const peers=new Map<number,RTCPeerConnection>(),pendingIce=new Map<number,RTCIceCandidateInit[]>();
let heartbeatTimer:ReturnType<typeof setInterval>|undefined,statusTimer:ReturnType<typeof setInterval>|undefined,messageTimer:ReturnType<typeof setInterval>|undefined,leaveSent=false;
const csrf=()=>(document.querySelector('meta[name="csrf-token"]') as HTMLMetaElement)?.content??'';async function api(url:string,options:RequestInit={}){const r=await fetch(url,{...options,credentials:'same-origin',headers:{Accept:'application/json','Content-Type':'application/json','X-CSRF-TOKEN':csrf()}});const p=await r.json();if(!r.ok)throw new Error(p.message??'Unable to continue.');return p}
const isHost=()=>room.value&&Number(room.value.host_id)===me&&room.value.status==='live';function beginLifecycle(){clearInterval(heartbeatTimer);clearInterval(statusTimer);if(isHost()){api(`/api/v1/live/${room.value.public_id}/heartbeat`,{method:'POST'}).catch(()=>{});heartbeatTimer=setInterval(()=>api(`/api/v1/live/${room.value.public_id}/heartbeat`,{method:'POST'}).catch(()=>{}),15000)}else if(room.value?.status==='live'){statusTimer=setInterval(async()=>{try{const current=(await api(`/api/v1/live/${room.value.public_id}`)).data.stream;if(current.status!=='live')room.value.status='ended'}catch{}},15000)}}function endOnLeave(){if(!isHost()||leaveSent)return;leaveSent=true;const url=`/api/v1/live/${room.value.public_id}/end`;if(navigator.sendBeacon)navigator.sendBeacon(url,new Blob([],{type:'text/plain;charset=UTF-8'}));else fetch(url,{method:'POST',credentials:'same-origin',keepalive:true,headers:{Accept:'application/json','X-CSRF-TOKEN':csrf()}}).catch(()=>{})}
async function load(){streams.value=(await api('/api/v1/live')).data}function mergeMessages(items:any[]){const known=new Set(messages.value.map(item=>String(item.id)));for(const item of items)if(!known.has(String(item.id))){messages.value.push(item);known.add(String(item.id))}}async function refreshRoom(){if(!room.value)return;try{const p=(await api('/api/v1/live/'+room.value.public_id)).data;Object.assign(room.value,p.stream);mergeMessages(p.messages)}catch{}}async function open(id:string){const p=(await api('/api/v1/live/'+id)).data;room.value=p.stream;messages.value=p.messages;leaveSent=false;history.replaceState({},'',`/live/${id}`);await nextTick();if(preview.value&&camera.value)preview.value.srcObject=camera.value;await subscribe(id);if(Number(room.value.host_id)!==me&&room.value.status==='live')await api(`/api/v1/live/${id}/join`,{method:'POST'});clearInterval(messageTimer);messageTimer=setInterval(refreshRoom,3000);beginLifecycle()}
async function prepare(){error.value='';permissionHelp.value=false;if(!window.isSecureContext){error.value='Camera access requires https://sportsuniverse.co.za/live. It cannot work on the plain IP address.';permissionHelp.value=true;return}if(!navigator.mediaDevices?.getUserMedia){error.value='Update your browser or use Safari, Chrome, or Edge to broadcast.';permissionHelp.value=true;return}requesting.value=true;try{camera.value=await navigator.mediaDevices.getUserMedia({video:{facingMode:{ideal:'user'},width:{ideal:1280},height:{ideal:720}},audio:{echoCancellation:true,noiseSuppression:true}});creating.value=true;await nextTick();if(preview.value){preview.value.srcObject=camera.value;await preview.value.play().catch(()=>{})}}catch(e:any){permissionHelp.value=true;if(e.name==='NotAllowedError'||e.name==='SecurityError')error.value='Camera or microphone is blocked. Allow both in browser site settings, then tap Try again.';else if(e.name==='NotFoundError')error.value='No camera or microphone was found on this device.';else if(e.name==='NotReadableError')error.value='Another app is using the camera or microphone. Close it and try again.';else error.value='SportsUniverse could not start the camera and microphone. Check site permissions and try again.'}finally{requesting.value=false}}
async function start(){if(!title.value.trim())return;const p=await api('/api/v1/live',{method:'POST',body:JSON.stringify({title:title.value,description:description.value})});creating.value=false;await open(p.data.id)}async function end(){leaveSent=true;clearInterval(heartbeatTimer);await api(`/api/v1/live/${room.value.public_id}/end`,{method:'POST'});stopCamera();room.value.status='ended'}
async function send(kind?:string){const payload=kind?{reaction:kind}:{body:body.value.trim()};if(!payload.body&&!kind)return;const p=(await api(`/api/v1/live/${room.value.public_id}/messages`,{method:'POST',body:JSON.stringify(payload)})).data;if(!kind)mergeMessages([p]);body.value='';if(kind){reaction.value=kind;setTimeout(()=>reaction.value='',700)}}
const rtcConfig={iceServers:[{urls:'stun:stun.l.google.com:19302'},{urls:'stun:stun1.l.google.com:19302'}]};async function signal(target:number,kind:string,payload:any){await api(`/api/v1/live/${room.value.public_id}/signal`,{method:'POST',body:JSON.stringify({target_id:target,kind,payload})})}async function flushIce(sender:number,pc:RTCPeerConnection){for(const candidate of pendingIce.get(sender)??[])await pc.addIceCandidate(candidate).catch(()=>{});pendingIce.delete(sender)}function peer(target:number,host=false){if(peers.has(target))return peers.get(target)!;const pc=new RTCPeerConnection(rtcConfig);peers.set(target,pc);if(host)camera.value?.getTracks().forEach(track=>pc.addTrack(track,camera.value!));pc.onicecandidate=e=>{if(e.candidate)signal(target,'ice',e.candidate.toJSON()).catch(()=>{})};pc.ontrack=async e=>{await nextTick();if(remoteVideo.value){remoteVideo.value.srcObject=e.streams[0];await remoteVideo.value.play().catch(()=>{})}};pc.onconnectionstatechange=()=>{if(['failed','closed'].includes(pc.connectionState)){pc.close();peers.delete(target);pendingIce.delete(target)}};return pc}async function offer(viewer:number){if(!camera.value)return;const pc=peer(viewer,true),description=await pc.createOffer();await pc.setLocalDescription(description);await signal(viewer,'offer',description)}async function handleSignal(event:any){if(Number(event.target_id)!==me)return;const sender=Number(event.sender_id);if(event.kind==='offer'){const pc=peer(sender);await pc.setRemoteDescription(event.payload);await flushIce(sender,pc);const answer=await pc.createAnswer();await pc.setLocalDescription(answer);await signal(sender,'answer',answer)}else if(event.kind==='answer'){const pc=peers.get(sender);if(pc){await pc.setRemoteDescription(event.payload);await flushIce(sender,pc)}}else if(event.kind==='ice'){const pc=peer(sender,Number(room.value?.host_id)===me);if(pc.remoteDescription)await pc.addIceCandidate(event.payload).catch(()=>{});else pendingIce.set(sender,[...(pendingIce.get(sender)??[]),event.payload])}}function subscribe(id:string){return new Promise<void>(resolve=>{if(!window.Echo){resolve();return}const channel:any=window.Echo.channel('live.'+id);channel.listen('.live.activity',(event:any)=>{if(event.type==='message')mergeMessages([event]);if(event.type==='viewer_join'){room.value.viewer_count=event.count;if(Number(room.value.host_id)===me)offer(Number(event.viewer_id)).catch(()=>{})}if(event.type==='signal')handleSignal(event).catch(()=>{});if(event.type==='ended')room.value.status='ended';if(event.type==='reaction'){reaction.value=event.reaction;setTimeout(()=>reaction.value='',700)}});let resolved=false;const ready=()=>{if(!resolved){resolved=true;resolve()}};channel.subscribed(ready);setTimeout(ready,2500)})}
function toggleAudio(){muted.value=!muted.value;camera.value?.getAudioTracks().forEach(t=>t.enabled=!muted.value)}function toggleVideo(){videoOff.value=!videoOff.value;camera.value?.getVideoTracks().forEach(t=>t.enabled=!videoOff.value)}function stopCamera(){camera.value?.getTracks().forEach(t=>t.stop());camera.value=undefined}async function share(){const url=location.href;navigator.share?await navigator.share({title:room.value.title,url}).catch(()=>{}):await navigator.clipboard.writeText(url)}
onMounted(async()=>{window.addEventListener('pagehide',endOnLeave);window.addEventListener('beforeunload',endOnLeave);await load();if(props.initialStream)await open(props.initialStream)});onUnmounted(()=>{endOnLeave();clearInterval(heartbeatTimer);clearInterval(statusTimer);clearInterval(messageTimer);window.removeEventListener('pagehide',endOnLeave);window.removeEventListener('beforeunload',endOnLeave);stopCamera();peers.forEach(pc=>pc.close());peers.clear();pendingIce.clear();if(room.value)window.Echo?.leave('live.'+room.value.public_id)});
</script>
<template><Head title="Live"/><AppShell><main class="live-page"><header class="live-head"><div><span><Radio/> LIVE</span><h1>SportsUniverse Live</h1><p>Watch training, trials, match reactions and sporting stories as they happen.</p></div><button class="go-live" :disabled="requesting" @click="prepare"><Camera/>{{ requesting?'Requesting…':'Go LIVE' }}</button></header><p v-if="error" class="live-error">{{ error }}</p><div v-if="permissionHelp" class="permission-help"><strong>Enable camera and microphone</strong><ol><li>Tap the lock or site-settings icon beside the website address.</li><li>Set Camera and Microphone to Allow.</li><li>Return here and tap Try again.</li></ol><button class="go-live" :disabled="requesting" @click="prepare">Try again</button></div>
<section v-if="!room&&!creating"><div class="live-section-title"><div><h2>Live now</h2><small>{{ streams.length }} {{ streams.length === 1 ? 'broadcast' : 'broadcasts' }}</small></div><span v-if="streams.length"><Radio/> Happening now</span></div><div class="live-grid"><button v-for="item in streams" @click="open(item.id)"><div class="live-cover"><img v-if="item.image" :src="item.image"/><Radio/><b>LIVE</b><span><Users/>{{ item.viewer_count }}</span></div><strong>{{ item.title }}</strong><small>{{ item.host_name }}</small></button><div v-if="!streams.length" class="live-empty"><span class="live-empty-icon"><Radio/></span><h3>Nobody is live right now</h3><p>Start the first broadcast and invite your community to watch.</p><button :disabled="requesting" @click="prepare"><Camera/>{{ requesting ? 'Requesting…' : 'Start a broadcast' }}</button></div></div></section>
<section v-if="creating" class="live-create"><div class="live-camera"><video ref="preview" autoplay muted playsinline/><div class="camera-controls"><button @click="toggleAudio"><MicOff v-if="muted"/><Mic v-else/></button><button @click="toggleVideo"><VideoOff v-if="videoOff"/><Video v-else/></button><button @click="stopCamera();creating=false"><X/></button></div></div><form @submit.prevent="start"><span>PREPARE YOUR LIVE</span><h2>Add live details</h2><input v-model="title" class="su-input" maxlength="150" required placeholder="Give your live a title"/><textarea v-model="description" class="su-input" placeholder="What will viewers see?"/><p>Your camera and microphone are active only while you are live.</p><button class="go-live">Start LIVE</button></form></section>
<section v-if="room" class="live-room"><div class="live-stage"><div class="stage-placeholder"><video v-if="camera" ref="preview" autoplay muted playsinline/><video v-else-if="room.status==='live'" ref="remoteVideo" class="remote-live-video" autoplay muted playsinline controls/><template v-else><img v-if="room.image" :src="room.image"/><Video v-else/><p>This live has ended</p></template></div><div class="stage-top"><b>{{ room.status==='live'?'LIVE':'ENDED' }}</b><span><Users/>{{ room.viewer_count }}</span><button @click="share"><Share2/></button></div><div v-if="reaction" class="floating-reaction">{{ {heart:'❤️',fire:'🔥',clap:'👏',football:'⚽'}[reaction] }}</div><div class="stage-info"><strong>{{ room.host_name }}</strong><h2>{{ room.title }}</h2><p>{{ room.description }}</p></div></div><aside class="live-chat"><header><MessageCircle/><b>Live chat</b></header><div class="chat-scroll"><p v-for="m in messages"><b>{{ m.name }}</b> {{ m.body }}<span v-if="m.reaction">{{ {heart:'❤️',fire:'🔥',clap:'👏',football:'⚽'}[m.reaction] }}</span></p></div><div class="reactions"><button @click="send('heart')"><Heart/></button><button @click="send('fire')"><Flame/></button><button @click="send('clap')">👏</button><button @click="send('football')">⚽</button></div><form @submit.prevent="send()"><input v-model="body" placeholder="Say something…" maxlength="300"/><button><Send/></button></form><button v-if="camera" class="end-live" @click="end">End live</button></aside></section></main></AppShell></template>
<style scoped>.live-page{max-width:1250px;margin:auto;padding:30px}.live-head{display:flex;justify-content:space-between;align-items:center}.live-head span{display:flex;gap:6px;color:#ec2f73;font-weight:900}.live-head h1{font-size:clamp(30px,5vw,50px);margin:5px 0}.go-live{display:flex;align-items:center;justify-content:center;gap:7px;padding:13px 22px;color:white;border:0;border-radius:999px;background:linear-gradient(135deg,#ef286d,#7c36ee);font-weight:800}.live-section-title{display:flex;align-items:center;justify-content:space-between;margin:28px 0 14px}.live-section-title h2{margin:0 0 3px;font-size:22px}.live-section-title small{color:#64748b}.live-section-title>span{display:flex;align-items:center;gap:6px;color:#ec2f73;font-size:12px;font-weight:800}.live-section-title>span svg{width:16px}.live-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}.live-grid>button{border:0;background:none;text-align:left}.live-cover{position:relative;display:grid;aspect-ratio:9/13;place-items:center;overflow:hidden;color:white;border-radius:18px;background:linear-gradient(145deg,#10263d,#42133a)}.live-cover img{width:100%;height:100%;object-fit:cover}.live-cover>b,.stage-top b{position:absolute;top:12px;left:12px;padding:5px 8px;border-radius:6px;background:#ee2669}.live-cover span{position:absolute;top:12px;right:12px;display:flex;gap:4px}.live-cover svg{width:42px}.live-grid>button>strong,.live-grid>button>small{display:block;margin-top:8px}.live-empty{grid-column:1/-1;display:flex;min-height:270px;padding:40px;align-items:center;justify-content:center;flex-direction:column;text-align:center;border:1px dashed #bbc8d8;border-radius:18px;background:linear-gradient(145deg,#fff,#f7f4ff)}.live-empty-icon{display:grid;width:58px;height:58px;place-items:center;color:#ec2f73;border-radius:50%;background:#ffe7f0}.live-empty-icon svg{width:27px}.live-empty h3{margin:18px 0 7px;font-size:20px}.live-empty p{max-width:360px;margin:0;color:#64748b}.live-empty>button{display:flex;margin-top:20px;padding:11px 18px;align-items:center;gap:7px;color:white;border:0;border-radius:999px;background:#171d2b;font-weight:800}.live-empty>button svg{width:18px}.live-create,.live-room{display:grid;grid-template-columns:minmax(0,2fr) minmax(280px,1fr);gap:18px;margin-top:25px}.live-camera,.live-stage{position:relative;overflow:hidden;aspect-ratio:9/14;max-height:75vh;border-radius:22px;background:#080b11}.live-camera video,.stage-placeholder,.stage-placeholder video,.stage-placeholder img{width:100%;height:100%;object-fit:cover}.camera-controls{position:absolute;bottom:20px;display:flex;width:100%;gap:10px;justify-content:center}.camera-controls button{display:grid;width:48px;height:48px;place-items:center;color:white;border:0;border-radius:50%;background:#ffffff29}.live-create form,.live-chat{display:flex;flex-direction:column;gap:14px;padding:22px;border:1px solid #dce4ed;border-radius:18px;background:white}.live-create textarea{min-height:130px}.stage-top{position:absolute;top:0;display:flex;width:100%;gap:10px;padding:12px;justify-content:flex-end;color:white}.stage-top b{position:static;margin-right:auto}.stage-top span{display:flex;align-items:center;gap:4px}.stage-top button{color:white;border:0;background:none}.stage-info{position:absolute;bottom:0;width:100%;padding:50px 20px 20px;color:white;background:linear-gradient(transparent,#000c)}.floating-reaction{position:absolute;right:30px;bottom:150px;font-size:60px;animation:float .7s}.chat-scroll{flex:1;min-height:250px;overflow:auto}.chat-scroll p{font-size:13px}.reactions{display:flex;gap:8px}.reactions button{display:grid;width:42px;height:42px;place-items:center;border:0;border-radius:50%;background:#f1f4f8}.live-chat form{display:flex}.live-chat input{flex:1;padding:12px;border:1px solid #d9e1ea;border-radius:999px}.live-chat form button{border:0;background:none}.end-live{padding:12px;color:white;border:0;border-radius:9px;background:#e52f56}.live-error{color:#a41632}@keyframes float{to{transform:translateY(-80px);opacity:0}}@media(max-width:760px){.live-page{padding:20px 16px 105px}.live-head{position:relative;display:block}.live-head>div{min-width:0}.live-head>div>span{height:46px;align-items:center;font-size:14px}.live-head>div>span svg{width:18px}.live-head h1{margin:10px 0 0;font-size:29px;line-height:1.12;letter-spacing:-.025em}.live-head p{display:none}.live-head>.go-live{position:absolute;top:0;right:0;min-width:112px;height:46px;padding:0 16px;white-space:nowrap;font-size:13px}.live-head>.go-live svg{width:18px}.live-section-title{margin:24px 0 12px}.live-section-title h2{font-size:19px}.live-grid{grid-template-columns:repeat(2,1fr)}.live-create,.live-room{grid-template-columns:1fr}.live-camera,.live-stage{max-height:65vh}.live-chat{min-height:350px}.live-empty{min-height:250px;padding:28px 20px;border-radius:20px}.live-empty-icon{width:52px;height:52px}.live-empty h3{margin-top:15px;font-size:18px}.live-empty p{font-size:14px;line-height:1.5}.live-empty>button{margin-top:17px}.permission-help{margin-top:16px}.live-error{margin-top:16px;font-size:14px}}@media(max-width:380px){.live-head h1{font-size:27px}.live-head>.go-live{min-width:106px;padding:0 13px}.live-empty{min-height:235px}}</style>
